document.addEventListener('DOMContentLoaded', () => { const searchInput = document.getElementById('docSearch'); const clearBtn = document.getElementById('clearSearch'); const docSections = document.querySelectorAll('.doc-section'); const docsContent = document.querySelector('.docs-content'); const searchIndex = buildSearchIndex(); if (searchInput) { let debounceTimeout; function debounce(func, delay) { return function (...args) { clearTimeout(debounceTimeout); debounceTimeout = setTimeout(() => func.apply(this, args), delay); }; } document.addEventListener('keydown', (e) => { if (e.key === '/' && document.activeElement !== searchInput) { e.preventDefault(); searchInput.focus(); } if (e.key === 'Escape' && document.activeElement === searchInput) { searchInput.blur(); clearSearch(); } }); searchInput.addEventListener('keydown', (e) => { if (e.key === 'ArrowDown' || e.key === 'ArrowUp') { e.preventDefault(); navigateResults(e.key === 'ArrowDown' ? 1 : -1); } if (e.key === 'Enter') { e.preventDefault(); const activeResult = document.querySelector('.search-result-active'); if (activeResult) { const sectionId = activeResult.getAttribute('data-section'); jumpToSection(sectionId); } else { const firstVisible = document.querySelector('.doc-section:not([style*="display: none"])'); if (firstVisible) { jumpToSection(firstVisible.id); } } if (window.innerWidth <= 1024) { searchInput.blur(); if (docsSidebar && docsSidebar.classList.contains('active')) { toggleSidebar(); } } } }); searchInput.addEventListener('input', debounce((e) => { const query = e.target.value.toLowerCase().trim(); if (query) { clearBtn.style.display = 'block'; performSearch(query); } else { clearBtn.style.display = 'none'; clearSearch(); } }, 150)); if (clearBtn) { clearBtn.addEventListener('click', () => { searchInput.value = ''; clearBtn.style.display = 'none'; clearSearch(); searchInput.focus(); }); } } function buildSearchIndex() { const index = []; docSections.forEach(section => { const heading = section.querySelector('h2'); const headingText = heading ? heading.textContent.trim() : ''; const subheadings = Array.from(section.querySelectorAll('h3')).map(h => h.textContent.trim()); const codeBlocks = Array.from(section.querySelectorAll('code')).map(c => c.textContent.trim()); const paragraphs = Array.from(section.querySelectorAll('p')).map(p => p.textContent.trim()); const listItems = Array.from(section.querySelectorAll('li')).map(li => li.textContent.trim()); index.push({ id: section.id, title: headingText, subheadings, content: [...paragraphs, ...listItems].join(' '), code: codeBlocks.join(' '), fullText: section.textContent.toLowerCase() }); }); return index; } function performSearch(query) { const results = []; const queryWords = query.split(/\s+/).filter(w => w.length > 0); searchIndex.forEach(entry => { let score = 0; const lowerTitle = entry.title.toLowerCase(); const lowerContent = entry.content.toLowerCase(); const lowerCode = entry.code.toLowerCase(); queryWords.forEach(word => { if (lowerTitle.includes(word)) score += 10; entry.subheadings.forEach(sh => { if (sh.toLowerCase().includes(word)) score += 5; }); if (lowerCode.includes(word)) score += 3; if (lowerContent.includes(word)) score += 1; }); if (score > 0 || entry.fullText.includes(query)) { results.push({ ...entry, score: score || 0.5 }); } }); results.sort((a, b) => b.score - a.score); docSections.forEach(section => { const match = results.find(r => r.id === section.id); if (match) { section.style.display = 'block'; highlightMatches(section, queryWords); } else { section.style.display = 'none'; removeHighlights(section); } }); filterSidebarLinks(results.map(r => r.id)); updateResultsStatus(results.length, query); showResultsDropdown(results, query); } function highlightMatches(section, queryWords) { removeHighlights(section); const targets = section.querySelectorAll('p, li, h3, h4, strong, .step-content h3'); targets.forEach(el => { if (el.closest('pre') || el.closest('code') || el.closest('.code-block-wrapper')) return; queryWords.forEach(word => { if (word.length < 2) return; highlightTextInElement(el, word); }); }); } function highlightTextInElement(element, word) { const walker = document.createTreeWalker(element, NodeFilter.SHOW_TEXT, null, false); const textNodes = []; while (walker.nextNode()) { textNodes.push(walker.currentNode); } textNodes.forEach(node => { const text = node.textContent; const lowerText = text.toLowerCase(); const index = lowerText.indexOf(word.toLowerCase()); if (index >= 0) { const before = text.slice(0, index); const matched = text.slice(index, index + word.length); const after = text.slice(index + word.length); const mark = document.createElement('mark'); mark.className = 'search-match'; mark.textContent = matched; const frag = document.createDocumentFragment(); if (before) frag.appendChild(document.createTextNode(before)); frag.appendChild(mark); if (after) frag.appendChild(document.createTextNode(after)); node.parentNode.replaceChild(frag, node); } }); } function removeHighlights(section) { const marks = section.querySelectorAll('mark.search-match'); marks.forEach(mark => { const parent = mark.parentNode; parent.replaceChild(document.createTextNode(mark.textContent), mark); parent.normalize(); }); } function filterSidebarLinks(visibleIds) { const allSidebarLinks = document.querySelectorAll('.sidebar-section ul li a'); const sidebarSections = document.querySelectorAll('.sidebar-section'); if (visibleIds.length === 0 || visibleIds.length === searchIndex.length) { allSidebarLinks.forEach(link => { link.closest('li').style.display = ''; link.classList.remove('search-sidebar-match'); }); sidebarSections.forEach(s => s.style.display = ''); return; } allSidebarLinks.forEach(link => { const href = link.getAttribute('href').replace('#', ''); const li = link.closest('li'); if (visibleIds.includes(href)) { li.style.display = ''; link.classList.add('search-sidebar-match'); } else { li.style.display = 'none'; link.classList.remove('search-sidebar-match'); } }); sidebarSections.forEach(section => { const visibleLinks = section.querySelectorAll('ul li:not([style*="display: none"])'); section.style.display = visibleLinks.length > 0 ? '' : 'none'; }); } function showResultsDropdown(results, query) { let dropdown = document.getElementById('searchResultsDropdown'); if (results.length === 0) { if (dropdown) dropdown.remove(); return; } if (!dropdown) { dropdown = document.createElement('div'); dropdown.id = 'searchResultsDropdown'; dropdown.className = 'search-results-dropdown'; searchInput.closest('.search-box').appendChild(dropdown); } dropdown.innerHTML = results.map((r, i) => { const snippet = getSnippet(r, query); return ` <button class="search-result-item ${i === 0 ? 'search-result-active' : ''}" data-section="${r.id}" tabindex="-1"> <span class="search-result-title">${escapeHtml(r.title)}</span> <span class="search-result-snippet">${snippet}</span> </button> `; }).join(''); dropdown.querySelectorAll('.search-result-item').forEach(item => { item.addEventListener('click', () => { jumpToSection(item.getAttribute('data-section')); dropdown.remove(); }); }); } function getSnippet(entry, query) { const text = entry.content; const lower = text.toLowerCase(); const idx = lower.indexOf(query); if (idx === -1) return ''; const start = Math.max(0, idx - 40); const end = Math.min(text.length, idx + query.length + 60); let snippet = text.slice(start, end).trim(); if (start > 0) snippet = '…' + snippet; if (end < text.length) snippet = snippet + '…'; const escaped = escapeHtml(snippet); const escapedQuery = escapeHtml(query); return escaped.replace( new RegExp(`(${escapedQuery.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})`, 'gi'), '<strong>$1</strong>' ); } function escapeHtml(text) { const div = document.createElement('div'); div.textContent = text; return div.innerHTML; } let currentResultIndex = -1; function navigateResults(direction) { const items = document.querySelectorAll('.search-result-item'); if (items.length === 0) return; items.forEach(item => item.classList.remove('search-result-active')); currentResultIndex += direction; if (currentResultIndex < 0) currentResultIndex = items.length - 1; if (currentResultIndex >= items.length) currentResultIndex = 0; items[currentResultIndex].classList.add('search-result-active'); items[currentResultIndex].scrollIntoView({ block: 'nearest' }); } function jumpToSection(sectionId) { const section = document.getElementById(sectionId); if (!section) return; const navHeight = document.querySelector('.navbar').offsetHeight; const targetPosition = section.getBoundingClientRect().top + window.scrollY - navHeight - 20; window.scrollTo({ top: targetPosition, behavior: 'smooth' }); section.classList.add('search-jump-flash'); setTimeout(() => section.classList.remove('search-jump-flash'), 1000); } function updateResultsStatus(count, query) { let statusEl = document.getElementById('searchStatus'); let noResultsMsg = document.getElementById('noResults'); if (count > 0) { if (noResultsMsg) noResultsMsg.remove(); if (!statusEl) { statusEl = document.createElement('div'); statusEl.id = 'searchStatus'; statusEl.className = 'search-status'; searchInput.closest('.search-box').appendChild(statusEl); } statusEl.textContent = `${count} section${count !== 1 ? 's' : ''} found`; statusEl.style.display = 'block'; } else { if (statusEl) statusEl.style.display = 'none'; if (!noResultsMsg) { noResultsMsg = document.createElement('div'); noResultsMsg.id = 'noResults'; noResultsMsg.className = 'no-results'; docsContent.prepend(noResultsMsg); } noResultsMsg.innerHTML = ` <i class="fas fa-search"></i> <p>No results for "<strong>${escapeHtml(query)}</strong>"</p> <p class="no-results-hint">Try different keywords or <button class="no-results-clear" onclick="document.getElementById('clearSearch').click()">clear search</button></p> `; } } function clearSearch() { docSections.forEach(section => { section.style.display = 'block'; removeHighlights(section); }); filterSidebarLinks([]); const dropdown = document.getElementById('searchResultsDropdown'); if (dropdown) dropdown.remove(); const statusEl = document.getElementById('searchStatus'); if (statusEl) statusEl.style.display = 'none'; const noResultsMsg = document.getElementById('noResults'); if (noResultsMsg) noResultsMsg.remove(); currentResultIndex = -1; } document.addEventListener('click', (e) => { if (!e.target.closest('.search-box')) { const dropdown = document.getElementById('searchResultsDropdown'); if (dropdown) dropdown.remove(); } }); if (searchInput) { searchInput.addEventListener('focus', () => { const query = searchInput.value.toLowerCase().trim(); if (query) { performSearch(query); } }); } const mobileSidebarToggle = document.getElementById('mobileSidebarToggle'); const docsSidebar = document.getElementById('docsSidebar'); const sidebarBackdrop = document.getElementById('sidebarBackdrop'); if (mobileSidebarToggle && docsSidebar && sidebarBackdrop) { function toggleSidebar() { const isActive = docsSidebar.classList.toggle('active'); sidebarBackdrop.classList.toggle('active', isActive); mobileSidebarToggle.innerHTML = isActive ? '<i class="fas fa-times"></i><span>Close</span>' : '<i class="fas fa-list-ul"></i><span>Menu</span>'; document.body.style.overflow = isActive ? 'hidden' : ''; } mobileSidebarToggle.addEventListener('click', toggleSidebar); sidebarBackdrop.addEventListener('click', toggleSidebar); const sidebarLinks = docsSidebar.querySelectorAll('ul li a'); sidebarLinks.forEach(link => { link.addEventListener('click', () => { if (window.innerWidth <= 1024) { toggleSidebar(); } }); }); } const copyButtons = document.querySelectorAll('.copy-btn'); copyButtons.forEach(btn => { btn.addEventListener('click', async () => { const targetId = btn.getAttribute('data-target'); let codeElement; if (targetId) { codeElement = document.getElementById(targetId); } else { const codeBlock = btn.closest('.code-block-wrapper'); codeElement = codeBlock.querySelector('code'); } if (codeElement) { try { await navigator.clipboard.writeText(codeElement.innerText); const originalIcon = btn.innerHTML; btn.innerHTML = '<i class="fas fa-check"></i>'; btn.style.color = '#4ade80'; setTimeout(() => { btn.innerHTML = originalIcon; btn.style.color = ''; }, 2000); } catch (err) { console.error('Failed to copy text: ', err); } } }); }); const sections = document.querySelectorAll('.doc-section'); const sidebarLinksAll = document.querySelectorAll('.docs-sidebar a'); function highlightActiveSection() { if (searchInput && searchInput.value.trim()) return; let current = ''; sections.forEach(section => { const sectionTop = section.offsetTop; if (window.scrollY >= sectionTop - 150) { current = section.getAttribute('id'); } }); sidebarLinksAll.forEach(link => { link.classList.remove('active'); if (link.getAttribute('href') === `#${current}`) { link.classList.add('active'); } }); } if (sidebarLinksAll.length > 0) { window.addEventListener('scroll', highlightActiveSection, { passive: true }); highlightActiveSection(); } sidebarLinksAll.forEach(link => { link.addEventListener('click', (e) => { e.preventDefault(); const targetId = link.getAttribute('href'); const targetSection = document.querySelector(targetId); if (targetSection) { if (searchInput && searchInput.value.trim()) { searchInput.value = ''; if (clearBtn) clearBtn.style.display = 'none'; clearSearch(); } const navHeight = document.querySelector('.navbar').offsetHeight; const targetPosition = targetSection.getBoundingClientRect().top + window.scrollY - navHeight - 20; window.scrollTo({ top: targetPosition, behavior: 'smooth' }); } }); }); });